package com.chaobo.scm.supplier.infrastructure.integration;
import org.apache.dubbo.config.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Component;import java.util.concurrent.ConcurrentHashMap;
@Component public class DubboReferenceFactory{private final ApplicationConfig application;private final RegistryConfig registry;private final int timeout;private final ConcurrentHashMap<Class<?>,Object> clients=new ConcurrentHashMap<>();public DubboReferenceFactory(@Value("${spring.application.name}")String app,@Value("${scm.dubbo.registry-address:N/A}")String address,@Value("${scm.dubbo.timeout-ms:2000}")int timeout){this.application=new ApplicationConfig(app);this.registry=new RegistryConfig(address);this.timeout=timeout;}@SuppressWarnings("unchecked")public <T>T client(Class<T> type){return(T)clients.computeIfAbsent(type,this::create);}private Object create(Class<?> type){var reference=new ReferenceConfig<>();reference.setApplication(application);reference.setRegistry(registry);reference.setInterface(type);reference.setProtocol("tri");reference.setCheck(false);reference.setLazy(true);reference.setTimeout(timeout);reference.setRetries(0);return reference.get();}}
